INSERT INTO `email_templates` (`id`, `subject`, `groupId`, `webshopId`, `organizationId`, `type`, `text`, `html`, `json`, `updatedAt`, `createdAt`) VALUES
('f2f42db2-79c0-4d5e-b9f3-bf214f63e99e', 'Je persoonlijke kortingscode', NULL, NULL, NULL, 'DefaultWebshopDiscountCodesEmail', '{{greeting}}\n\nJe persoonlijke kortingscode is {{discountCode}}.\n\nGebruik je code via deze link:\n{{discountUrl}}\n\nMet vriendelijke groeten,\n{{organizationName}}', '<!DOCTYPE html>\n<html>\n<head>\n<meta charset="utf-8" />\n<meta http-equiv="X-UA-Compatible" content="IE=edge" />\n<meta name="viewport" content="width=device-width,initial-scale=1.0" />\n<title>Je persoonlijke kortingscode</title>\n</head>\n<body>\n<p>{{greeting}}</p><p><br></p><p>Je persoonlijke kortingscode is <strong>{{discountCode}}</strong>.</p><p><br></p><div data-type="smartButton" data-id="discountUrl"><a href="{{discountUrl}}">Bestel met je kortingscode</a></div><p><br></p><p>Met vriendelijke groeten,</p><p>{{organizationName}}</p>\n</body>\n</html>', '{"value":{"type":"doc","content":[{"type":"paragraph","content":[{"type":"smartVariable","attrs":{"id":"greeting"}}]},{"type":"paragraph"},{"type":"paragraph","content":[{"text":"Je persoonlijke kortingscode is ","type":"text"},{"type":"smartVariable","attrs":{"id":"discountCode"}},{"text":".","type":"text"}]},{"type":"paragraph"},{"type":"smartButton","attrs":{"id":"discountUrl"},"content":[{"text":"Bestel met je kortingscode","type":"text"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"text":"Met vriendelijke groeten,","type":"text"}]},{"type":"paragraph","content":[{"type":"smartVariable","attrs":{"id":"organizationName"}}]}]},"version":399}', NOW(), NOW())
